import{_ as n,c as t,o,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.52: Claude 3.5 Sonnet Support, Bash Tool Loading Animation, Major Desktop Improvements","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.52.md","filePath":"en/changelog/v1.1.52.md","lastUpdated":1772014034000}'),l={name:"en/changelog/v1.1.52.md"};function r(s,a,d,h,c,p){return o(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-52-claude-3-5-sonnet-support-bash-tool-loading-animation-major-desktop-improvements" tabindex="-1">v1.1.52: Claude 3.5 Sonnet Support, Bash Tool Loading Animation, Major Desktop Improvements <a class="header-anchor" href="#v1-1-52-claude-3-5-sonnet-support-bash-tool-loading-animation-major-desktop-improvements" aria-label="Permalink to “v1.1.52: Claude 3.5 Sonnet Support, Bash Tool Loading Animation, Major Desktop Improvements”">​</a></h1><p><strong>Release Date</strong>: February 05, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update enables Claude 3.5 Sonnet (new) model, TUI adds Bash tool loading animation, fixes multiple provider compatibility issues, and desktop significantly improves terminal stability and file tree sync.</p><hr><h2 id="new-feature-claude-3-5-sonnet-new-model-support" tabindex="-1">New Feature: Claude 3.5 Sonnet (new) Model Support <a class="header-anchor" href="#new-feature-claude-3-5-sonnet-new-model-support" aria-label="Permalink to “New Feature: Claude 3.5 Sonnet (new) Model Support”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Enabled Claude 3.5 Sonnet (new) model, now available directly in OpenCode.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>If you&#39;ve already configured Anthropic API Key, you can directly select Claude 3.5 Sonnet (new) in the model selector.</p><hr><h2 id="new-feature-bash-tool-loading-animation" tabindex="-1">New Feature: Bash Tool Loading Animation <a class="header-anchor" href="#new-feature-bash-tool-loading-animation" aria-label="Permalink to “New Feature: Bash Tool Loading Animation”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When executing Bash commands in TUI, a rotating loading animation now displays to let you know the command is running.</p><h3 id="what-s-the-use" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>Previously, when executing long-running commands, the interface looked frozen. Now with the loading animation, you can clearly see the command is running.</p><hr><h2 id="new-feature-remote-server-terminal-connection" tabindex="-1">New Feature: Remote Server Terminal Connection <a class="header-anchor" href="#new-feature-remote-server-terminal-connection" aria-label="Permalink to “New Feature: Remote Server Terminal Connection”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Terminal now supports remote server connections and fixes GLIBC compatibility issues.</p><h3 id="what-s-the-use-1" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use-1" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>If you use OpenCode desktop on a remote server, terminal connections are more stable and reliable.</p><hr><h2 id="new-feature-thinking-blocks-keyboard-shortcut-binding" tabindex="-1">New Feature: Thinking Blocks Keyboard Shortcut Binding <a class="header-anchor" href="#new-feature-thinking-blocks-keyboard-shortcut-binding" aria-label="Permalink to “New Feature: Thinking Blocks Keyboard Shortcut Binding”">​</a></h2><h3 id="what-s-updated-3" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-3" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>You can now bind the show/hide Thinking Blocks function to custom keyboard shortcuts.</p><h3 id="how-to-use-1" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to Use?”">​</a></h3><p>Set keyboard shortcut bindings in the config file:</p><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/06b-keybinds.html">Keybinds Configuration</a></p><hr><h2 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to “Bug Fixes”">​</a></h2><h3 id="kimi-k2-5-image-reading" tabindex="-1">Kimi K2.5 Image Reading <a class="header-anchor" href="#kimi-k2-5-image-reading" aria-label="Permalink to “Kimi K2.5 Image Reading”">​</a></h3><p>Fixed the issue where images couldn&#39;t be read when using OpenAI-compatible providers (like Kimi K2.5).</p><h3 id="proxy-command-failure-causing-crash" tabindex="-1">Proxy Command Failure Causing Crash <a class="header-anchor" href="#proxy-command-failure-causing-crash" aria-label="Permalink to “Proxy Command Failure Causing Crash”">​</a></h3><p>Fixed the issue where proxy command failures would crash config initialization. Now silently ignores proxy command failures.</p><h3 id="github-copilot-plugin-headers" tabindex="-1">GitHub Copilot Plugin Headers <a class="header-anchor" href="#github-copilot-plugin-headers" aria-label="Permalink to “GitHub Copilot Plugin Headers”">​</a></h3><p>Fixed the issue where GitHub Copilot plugin wasn&#39;t correctly setting headers in non-TUI clients.</p><h3 id="plugin-installation-method" tabindex="-1">Plugin Installation Method <a class="header-anchor" href="#plugin-installation-method" aria-label="Permalink to “Plugin Installation Method”">​</a></h3><p>Fixed issues caused by plugin installation using <code>bun add</code>, changed to direct package.json manipulation.</p><h3 id="read-only-config-directory" tabindex="-1">Read-Only Config Directory <a class="header-anchor" href="#read-only-config-directory" aria-label="Permalink to “Read-Only Config Directory”">​</a></h3><p>Skip dependency installation in read-only config directories to avoid permission errors.</p><hr><h2 id="improvement-desktop" tabindex="-1">Improvement: Desktop <a class="header-anchor" href="#improvement-desktop" aria-label="Permalink to “Improvement: Desktop”">​</a></h2><h3 id="file-tree-real-time-sync" tabindex="-1">File Tree Real-time Sync <a class="header-anchor" href="#file-tree-real-time-sync" aria-label="Permalink to “File Tree Real-time Sync”">​</a></h3><p>File tree now stays in real-time sync with filesystem changes, no more inconsistent file states.</p><h3 id="terminal-stability" tabindex="-1">Terminal Stability <a class="header-anchor" href="#terminal-stability" aria-label="Permalink to “Terminal Stability”">​</a></h3><p>Multiple terminal stability fixes, including URL handling, end-of-line handling, etc.</p><h3 id="session-options" tabindex="-1">Session Options <a class="header-anchor" href="#session-options" aria-label="Permalink to “Session Options”">​</a></h3><p>Session options moved to session page for easier operation. Added session options functionality.</p><h3 id="workspace-switching" tabindex="-1">Workspace Switching <a class="header-anchor" href="#workspace-switching" aria-label="Permalink to “Workspace Switching”">​</a></h3><p>Automatically refresh workspace sessions and file contents when switching projects, avoiding displaying stale data.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Want to use Claude 3.5 Sonnet (new)</td><td>✅ Recommended</td></tr><tr><td>Using Kimi K2.5</td><td>✅ Recommended</td></tr><tr><td>Desktop users</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',56),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Enable Claude 3.5 Sonnet (new) model support</li><li>Silently ignore proxy command failures to prevent config initialization crashes</li><li>Ensure GitHub Copilot plugin properly sets headers when used in clients other than TUI</li><li>Bundle GitLab auth plugin directly instead of dynamic install</li><li>Fix plugin installation to use direct package.json manipulation instead of bun add</li><li>Fix image reading with OpenAI-compatible providers like Kimi K2.5 (@zhming0)</li><li>Downgrade xai ai-sdk package due to errors</li><li>Revert model autocomplete feature using models.dev schema reference</li><li>Add models.dev schema reference for model autocomplete in opencode.json (@remorses)</li><li>Adjust task tool description and input to reduce tool call failures with GPT models</li><li>Wait for dependencies before loading custom tools and plugins</li><li>Allow the function to hide or show thinking blocks to be bound to a key (@ariane-emory)</li><li>Skip dependency installation in read-only configuration directories (@shantur)</li><li>Ensure Kimi for Coding plan has thinking enabled by default for k2p5 (@monotykamary)</li><li>Fixed Cloudflare Workers AI provider</li><li>Prevent random hangs in plugin installs when using HTTP proxy by adding --no-cache flag</li><li>Session errors when attachment file not found are now handled gracefully</li><li>Support remote server connections in terminal and fix GLIBC compatibility (@lucas-jo)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add running spinner to bash tool in TUI (@goniz)</li><li>Add hover states to question tool tabs (@maharshi365)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>File changes not always available in app</li><li>File tree kept in sync with filesystem changes</li><li>Add Bosnian locale (@edoedac0)</li><li>Fix terminal URL handling issues</li><li>Remove extra horizontal padding around prompt input on mobile (@Brendonovich)</li><li>Refresh workspace sessions when switching projects (@neriousy)</li><li>Fixed terminal URL handling in the application</li><li>Fix terminal end-of-line handling issues</li><li>Refresh file contents when changing workspaces to prevent stale data (@ParkerSm1th)</li><li>Derive terminal WebSocket URL from browser origin instead of hardcoded localhost (@0xdsqr)</li><li>Last turn changes rendered in review pane</li><li>Safety triangle for sidebar hover to prevent menu from closing</li><li>Clear comments on prompt submission</li><li>Fix e2e test action in app</li><li>Terminal hyperlink clicks now work correctly</li><li>Fix dated e2e tests in app</li><li>Don&#39;t show scroll-to-bottom button unnecessarily</li><li>File tree not staying in sync across projects/sessions</li><li>Move session options to the session page</li><li>Add session options to app</li><li>Opened tabs follow created session</li><li>Removed compression from RPM bundle to save 15 minutes in CI (@goniz)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=n(l,[["render",r]]);export{u as __pageData,g as default};
